export function getScorecard(slug: string): ScorecardData | null {
  return scorecard[slug] ?? null;
}

export function formatPctSafe(n: number | undefined, digits = 1): string {
  if (n === undefined || n === null) return "—";
  return `${(n * 100).toFixed(digits)}%`;
}

export function formatMoneySafe(n: number | undefined): string {
  if (n === undefined || n === null) return "—";
  return `$${n.toLocaleString()}`;
}

// LOCALE_LABELS: maps Carnegie locale codes to readable strings
// 11 = City: Large, 12 = City: Midsize, 13 = City: Small
// 21 = Suburb: Large, 22 = Suburb: Midsize, 23 = Suburb: Small
// 31 = Town: Fringe, 32 = Town: Distant, 33 = Town: Remote
// 41 = Rural: Fringe, 42 = Rural: Distant, 43 = Rural: Remote
export function localeLabel(code: number | undefined): string {
  if (!code) return "Campus setting";
  const map: Record<number, string> = {
    11: "Large urban", 12: "Midsize urban", 13: "Small urban",
    21: "Suburban (large metro)", 22: "Suburban (midsize)", 23: "Suburban (small)",
    31: "Small town", 32: "Distant town", 33: "Remote town",
    41: "Rural", 42: "Rural", 43: "Rural",
  };
  return map[code] ?? "Campus setting";
}

